import{c as o,Q as e,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"OpenAI、Anthropic 都开始押注 FDE，FDE 才是 Agent 时代的 PMF 范式？","description":"","frontmatter":{"title":"OpenAI、Anthropic 都开始押注 FDE，FDE 才是 Agent 时代的 PMF 范式？","author":"Kafka (@kfk_ai) — CS 科班，AI Builder，美国八年","date":"2026-05-19T00:00:00.000Z","source":"https://x.com/kfk_ai/status/2056660897381425590","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-19-@kfk_ai-425590.md","filePath":"research/tweets/2026-05-19-@kfk_ai-425590.md","lastUpdated":1779894392000}'),n={name:"research/tweets/2026-05-19-@kfk_ai-425590.md"};function l(u,t,i,s,p,g){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="openai、anthropic-都开始押注-fde-fde-才是-agent-时代的-pmf-范式" tabindex="-1">OpenAI、Anthropic 都开始押注 FDE，FDE 才是 Agent 时代的 PMF 范式？ <a class="header-anchor" href="#openai、anthropic-都开始押注-fde-fde-才是-agent-时代的-pmf-范式" aria-label="Permalink to &quot;OpenAI、Anthropic 都开始押注 FDE，FDE 才是 Agent 时代的 PMF 范式？&quot;">​</a></h1><ul><li><strong>URL</strong>：<a href="https://x.com/kfk_ai/status/2056660897381425590" target="_blank" rel="noreferrer">https://x.com/kfk_ai/status/2056660897381425590</a></li><li><strong>作者</strong>：Kafka (@kfk_ai) — CS 科班，AI Builder，美国八年</li><li><strong>日期</strong>：2026-05-19</li><li><strong>互動</strong>：242 likes · 51 RT · 523 bookmarks · 73,257 views</li><li><strong>類型</strong>：Twitter Article（全文）</li></ul><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Agent时代的第一个共识浮出水面，模型已经不是瓶颈，人才是。</p><p>短短一周，OpenAI砸下40亿美元、Anthropic嵌进FIS的总部、Google官宣招几百人——三家AI巨头不约而同押注的，是同一个职位：FDE。</p><p>2026 年 5 月 11 日，OpenAI 宣布成立&quot;OpenAI Deployment Company&quot;，首期投入 40 亿美元，核心业务只有一件事，把工程师&quot;派进&quot;客户公司里，帮他们把 AI 跑起来。</p><p>仅仅一周前，Anthropic 刚把自己的工程师团队&quot;嵌&quot;进了金融科技巨头 FIS，要在 2026 年下半年让蒙特利尔银行（BMO）和 Amalgamated Bank 的反洗钱调查&quot;从几小时压缩到几分钟&quot;。再往前一周，Google Cloud CEO Thomas Kurian 亲自上 LinkedIn 招人，目标是&quot;招几百个&quot;，这条消息在 X 上获得了 130 万次浏览。</p><p>被三家公司同时押注的，是同一个职位：<strong>Forward Deployed Engineer</strong>，缩写 FDE，中文勉强可以译作&quot;前置部署工程师&quot;或&quot;驻场工程师&quot;。</p><p>一个原本只在 Palantir 这家&quot;另类&quot;软件公司流行了二十年的角色，突然在 2026 年成了整个 AI 行业最炙手可热的岗位。有人喊出口号：<strong>FDE 就是 Agent 时代的 PMF 范式</strong>。</p><p>这个判断，究竟是真知灼见，还是一厢情愿？要回答这个问题，得先把几件事讲清楚：FDE 到底是什么、为什么 2026 年它突然成了刚需、它和&quot;PMF&quot;这个词到底是什么关系——以及，它的局限在哪里。</p><hr><h2 id="一、fde-是什么-不是销售工程师-也不是咨询顾问" tabindex="-1">一、FDE 是什么：不是销售工程师，也不是咨询顾问 <a class="header-anchor" href="#一、fde-是什么-不是销售工程师-也不是咨询顾问" aria-label="Permalink to &quot;一、FDE 是什么：不是销售工程师，也不是咨询顾问&quot;">​</a></h2><p>先翻译两个术语，这是理解后面所有讨论的前提。</p><p><strong>PMF</strong>（Product-Market Fit，产品-市场契合）是硅谷创业圈的&quot;圣杯&quot;，意思是你的产品恰好满足了一个真实存在的市场需求，且市场愿意为它付费、复购、口碑传播。</p><p><strong>FDE</strong> 这个词面上是&quot;前置部署工程师&quot;，但它最早不是这么定义的。这个角色由 Palantir 在 2000 年代初发明，当时 Palantir 的客户是美国情报机构，一群&quot;既不能清楚说出自己要什么、也不能让你看他们的数据、甚至工作流程本身都在不断变化&quot;的人。</p><p>Palantir 的联合创始人 Shyam Sankar 有一句话很经典：<strong>&quot;如果一个问题能被需求文档解决，那它早就被解决了。&quot;</strong></p><p>所以 Palantir 做了一件当时很反常的事：不再问客户&quot;你想要什么&quot;，而是把工程师直接派进客户的办公室、军事基地，甚至飞机总装车间，让他们在客户身边写代码。这些人在 Palantir 内部被叫做&quot;Delta&quot;——他们要通过同样的工程师面试，但工作环境是空军基地、银行后台、医院 IT 系统，而不是 Palo Alto 的开放办公区。</p><p>这与传统软件公司常见的三种角色都不一样：</p><ul><li>销售工程师（Sales Engineer）负责售前演示，签完合同就走；</li><li>解决方案架构师（Solutions Architect）主要做技术咨询，不写生产代码；</li><li><strong>咨询顾问</strong>通常出方法论、做交付，但不参与厂商的产品迭代。</li></ul><p>FDE 的特殊之处在于：<strong>他写客户的生产代码，同时把客户场景里发现的共性问题反哺回厂商的核心产品</strong>。Palantir 内部的描述是：&quot;FDE 的工作范围像一个创业公司的 CTO——在小团队里端到端负责一个高风险项目。&quot;</p><p>到 2016 年，Palantir 的 FDE 数量一度超过了普通软件工程师。这家公司的整个产品形态——Foundry 平台，本质上就是从无数次 FDE 驻场项目中&quot;提炼&quot;出来的。一位曾在 Palantir 做了七年 FDE 的工程师后来总结说，这个模式叫&quot;<strong>砂石路到柏油路</strong>&quot;（gravel road to paved highway）：FDE 在客户现场修出无数条砂石路，产品团队从中找出走的人最多的那几条，把它铺成柏油路，变成平台能力。</p><h2 id="二、2026-年的拐点-为什么三大-ai-公司同时押注-fde" tabindex="-1">二、2026 年的拐点：为什么三大 AI 公司同时押注 FDE <a class="header-anchor" href="#二、2026-年的拐点-为什么三大-ai-公司同时押注-fde" aria-label="Permalink to &quot;二、2026 年的拐点：为什么三大 AI 公司同时押注 FDE&quot;">​</a></h2><p>Palantir 这个模式，在过去近二十年里，在硅谷主流圈被视为&quot;异类&quot;——大多数 SaaS 公司的建议都是&quot;别学 Palantir，毛利做不上来&quot;。但 2026 年，情况突然变了。</p><p><strong>5 月 4 日</strong>，Anthropic 和 FIS 宣布合作，Anthropic 的 Applied AI 团队和 FDE&quot;嵌入&quot;FIS 内部，共同设计金融犯罪 AI Agent。</p><p><strong>5 月 11 日</strong>，OpenAI 官宣成立 OpenAI Deployment Company（内部代号&quot;DeployCo&quot;），首期 40 亿美元投资，由 TPG 牵头，Advent、Bain Capital、Brookfield 联合领投，合计 19 家投资和咨询机构参与。同时宣布收购应用 AI 咨询公司 Tomoro，后者将带来约 150 名 FDE 和部署专家。</p><p><strong>5 月 12 日</strong>，Google Cloud CEO Thomas Kurian 在 LinkedIn 发文，宣布 Google Cloud 内部成立新的&quot;AI 聚焦组织&quot;，招聘&quot;几百名&quot;FDE。当时 Google Cloud 有 59 个相关职位在挂。</p><p>为什么是现在？为什么是同时？三家公司的判断指向同一个事实：<strong>Agent 时代的瓶颈，不在模型本身，而在部署</strong>。</p><p>埃森哲（Accenture）的&quot;Pulse of Change&quot;调研显示，只有 32% 的企业领导者报告说他们看到了&quot;持续的、企业范围内的 AI 影响&quot;。剩下 68% 的状态是——有试点、有 PPT、有 Demo，但没有规模化交付。IBM 在 2026 年初对 2000 名高管的调查中，&quot;执行速度&quot;被列为第三大战略优先级。</p><p>OpenAI 在公告里把这层逻辑说得很直白：<strong>&quot;过去几年，超过一百万家企业采用了我们的产品和 API。一个模式越来越清晰——下一阶段企业 AI 的胜负，取决于企业能多有效地把这项技术部署到真实业务场景中。&quot;</strong></p><p>换句话说，<strong>AI 模型本身的&quot;产品力&quot;边际收益在下降，但&quot;把模型变成可用系统&quot;的工程能力，边际收益在飙升</strong>。模型再强，如果跑不进银行的合规流程、跑不通保险公司的理赔系统、跑不进制造业的 MES 系统，它就只是 Demo，不是生意。</p><p>FDE，恰恰是这个转换器。</p><h2 id="三、agent-时代为什么对-fde-有-结构性需求" tabindex="-1">三、Agent 时代为什么对 FDE 有&quot;结构性需求&quot; <a class="header-anchor" href="#三、agent-时代为什么对-fde-有-结构性需求" aria-label="Permalink to &quot;三、Agent 时代为什么对 FDE 有&quot;结构性需求&quot;&quot;">​</a></h2><p>要理解为什么&quot;Agent&quot;和&quot;FDE&quot;是天作之合，需要先讲清楚 Agent 和此前 AI 形态的根本区别。</p><p>传统的 SaaS 产品，本质上是&quot;工具&quot;：你买 Salesforce，是买一套配置好的销售流程模板，你的人去使用它。<strong>工具的边界很清楚——它做什么、不做什么，在产品手册上写得明明白白</strong>。</p><p>而 <strong>Agent 是&quot;代劳&quot;</strong>：你不再是用它，而是让它替你做。一个反洗钱 Agent 不是给调查员一个更好的查询界面，而是直接帮调查员把&quot;从核心系统拉证据、对照已知洗钱模式、判断风险等级、撰写可疑活动报告（SAR）初稿&quot;这一整套工作流跑完。</p><p>这个差别带来三个后果：</p><p>第一，Agent 必须深度嵌入客户的真实工作流。一个 Agent 要&quot;代劳&quot;，就必须知道这家银行的合规边界在哪、哪些决定不能自动化、SAR 报告怎么写才会被监管接受、内部数据在哪些系统里、用什么字段命名。这些东西不在产品文档里，只在客户的&quot;机构肌肉记忆&quot;里。</p><p>第二，Agent 的失败是&quot;业务失败&quot;，不是&quot;功能失败&quot;。SaaS 少一个按钮，用户抱怨一下。Agent 漏判一笔可疑交易，银行被监管罚款。这意味着 Agent 的部署对&quot;领域知识&quot;和&quot;操作语境&quot;的依赖比任何前代软件都强。</p><p>第三，Agent 市场是一个&quot;既无成熟产品可对标、客户自己也不知道要什么&quot;的市场。这恰恰就是 Palantir 当年面对情报机构时的状况。客户能说出&quot;我希望 AML 调查更快&quot;，但说不出具体怎么定义&quot;快&quot;。这种问题用需求文档解决不了，只能让工程师进去观察、试、改、再观察。</p><p>Anthropic 的 FDE 职位描述把这套逻辑写得很清楚：<strong>&quot;在客户系统内部构建生产应用、交付 MCP 服务器、sub-agent、agent skills 等技术产物、提供企业环境下的白手套部署支持、识别可复用的部署模式并反哺回产品和工程团队。&quot;</strong></p><p>最后那一句——&quot;反哺回产品和工程团队&quot;——才是 FDE 模式真正的杠杆。这意味着每一次驻场，既是给客户做一次交付，也是给厂商做一次产品发现。FDE 是厂商伸进市场的触手，带回来的是真实场景的需求样本。</p><h2 id="四、fde-是不是-agent-时代的-pmf-范式-这里要给三个保留" tabindex="-1">四、FDE 是不是&quot;Agent 时代的 PMF 范式&quot;？这里要给三个保留 <a class="header-anchor" href="#四、fde-是不是-agent-时代的-pmf-范式-这里要给三个保留" aria-label="Permalink to &quot;四、FDE 是不是&quot;Agent 时代的 PMF 范式&quot;？这里要给三个保留&quot;">​</a></h2><p>保留一：FDE 可能在解决&quot;PMF 问题&quot;，也可能在&quot;掩盖 PMF 问题&quot;</p><p>PMF 的本意是&quot;产品契合市场&quot;——产品本身就是答案，客户拿来即用、续费、推荐。而 FDE 模式的本质是&quot;<strong>用人的工作弥合产品和市场的距离</strong>&quot;。</p><p>Gartner 的高级分析师 Alex Coqueiro 预测：到 2028 年，<strong>70% 的企业将被迫放弃由 FDE 主导的 Agent 项目</strong>，原因是&quot;厂商成本过高、内部缺乏独立演进的能力&quot;。</p><p>隐蔽的失败模式：<strong>&quot;FDE 工作量在多次部署后没有递减，就是依赖性而非能力被构建出来的信号。&quot;</strong></p><p>保留二：这是不是&quot;伪装成产品公司的咨询公司&quot;？</p><p>Constellation Research 的分析师 Larry Dignan：<strong>&quot;对厂商是 PMF 的范式，对客户可能是供应商锁定的前夜。&quot;</strong></p><p>保留三：FDE 可能正在被自己创造的工具替代</p><p>大量 FDE 初期做的&quot;部署简单 FAQ Agent&quot;工作，正在被产品本身吸收；FDE 的工作正在向更高抽象层迁移——多 Agent 架构、MCP 协议设计、语音 Agent、coding Agent 的编排。</p><p>South Park Commons 圆桌共识：<strong>模型越强，FDE 的价值不是下降，而是上升——但价值的来源变了</strong>。低层级集成工作被 AI 吃掉，FDE 的核心价值转向业务判断。</p><h2 id="五、对不同人-这件事的意义不一样" tabindex="-1">五、对不同人，这件事的意义不一样 <a class="header-anchor" href="#五、对不同人-这件事的意义不一样" aria-label="Permalink to &quot;五、对不同人，这件事的意义不一样&quot;">​</a></h2><p><strong>FDE 是 Agent 时代企业级 AI 从 Demo 走向生产系统的&quot;必要中间态&quot;，但它本身不是 PMF——它是寻找 PMF 的方法</strong>。</p><ul><li><strong>对 AI 厂商</strong>：FDE 不是收入业务，是产品发现机制。只有持续把驻场经验沉淀成可复用的产品能力——MCP server、agent skills、评估框架、部署模板——FDE 的投入才会有复利。</li><li><strong>对企业客户</strong>：Anthropic × FIS 合同关键一句：&quot;transfer knowledge so FIS can build and scale additional agents independently over time&quot;。如果合同里没有退出机制，FDE 就是温柔的锁定。</li><li><strong>对工程师</strong>：Google FDE 薪酬 $127K–$265K 基薪，资深平均 $238K，顶级接近 $400K，且预算来自客户扩展支出，抗裁员周期。</li><li><strong>对投资人</strong>：需要看&quot;砂石路变柏油路&quot;的速度——每次驻场后，产品本身的可复用能力提升了多少，而非当下毛利。</li></ul><hr><h2 id="分析" tabindex="-1">分析 <a class="header-anchor" href="#分析" aria-label="Permalink to &quot;分析&quot;">​</a></h2><h3 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h3><p>FDE（駐場工程師）成為 Agent 時代企業 AI 落地的必要中間態；OpenAI/Anthropic/Google 同步押注 $40B，但 FDE 是尋找 PMF 的方法而非 PMF 本身。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>三大 AI 巨頭同步押注 FDE</strong>：OpenAI $40B DeployCo、Anthropic 嵌入 FIS、Google 招聘數百名 FDE，一週內同時宣布</li><li><strong>模型不再是瓶頸，部署才是</strong>：Accenture 調研顯示 68% 企業只有 Demo 沒有規模化交付</li><li><strong>Agent 代勞 vs SaaS 工具</strong>：Agent 必須深度嵌入客戶業務邏輯、合規流程、機構記憶，無法靠文件需求規格</li><li><strong>砂石路到柏油路</strong>：FDE 驻場 → 識別共性問題 → 沉澱為平台產品能力，Palantir Foundry 即如此誕生</li><li><strong>三個保留</strong>：FDE 可能掩蓋 PMF 問題、供應商鎖定風險、被 AI 工具自身替代</li></ol><h3 id="關鍵數據" tabindex="-1">關鍵數據 <a class="header-anchor" href="#關鍵數據" aria-label="Permalink to &quot;關鍵數據&quot;">​</a></h3><ul><li>OpenAI DeployCo：首期投資 $40B，19 家機構參與，收購 Tomoro 帶入 150 名 FDE</li><li>Anthropic × FIS：AML 調查從數小時壓縮至數分鐘</li><li>Google Cloud：59 個 FDE 職位，招&quot;幾百名&quot;</li><li>Accenture：只有 32% 企業領導者看到&quot;持續的、企業範圍內的 AI 影響&quot;</li><li>Gartner：70% FDE 主導的 Agent 項目到 2028 年將被迫放棄</li><li>Google FDE 薪酬：$127K–$265K 基薪，資深平均 $238K</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>分析框架紮實</strong>：五節結構清晰，正面論述 + 三個保留，避免純 hype</li><li><strong>Workspace 相關性中等</strong>：本文為行業分析，對 Claude Code workspace 的直接可行動性有限；對 AI 產品/職涯方向有參考價值</li><li><strong>FDE 作為「Claude Code Agent」的商業背景</strong>：文中描述的 Agent 深度集成需求，正是 Anthropic Claude Code Agent 在企業場景需要解決的問題</li></ol><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>6/10</td><td>行業分析為主，對 workspace 直接可行動性有限；理解 Agent 時代商業邏輯有參考價值</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>系統性整合三大公司動向 + 反駁性保留，不是單純新聞匯總</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>引用官方公告、Gartner/Constellation 分析師、Accenture/IBM 調研，多方數據</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>提及 MCP server、sub-agent、agent skills，技術層次適中</td></tr><tr><td>E. 泛化性</td><td>7/10</td><td>適用所有 AI 產品/工程師/企業客戶，不限特定場景</td></tr></tbody></table><p><strong>加權總分</strong>：6×0.3 + 8×0.2 + 8×0.2 + 7×0.15 + 7×0.15 = <strong>7.1/10</strong></p><hr><h2 id="整合決策" tabindex="-1">整合決策 <a class="header-anchor" href="#整合決策" aria-label="Permalink to &quot;整合決策&quot;">​</a></h2><p><strong>Rule（知識性）</strong> — 了解 Agent 時代 FDE 商業模式，對評估 AI 工具在企業環境的部署策略有參考意義</p><p><strong>建議行動</strong>：無直接 workspace 改動；可參考「砂石路到柏油路」概念思考 memory-compactor 等工具如何從特殊場景沉澱為通用能力</p>',73)])])}const h=o(n,[["render",l]]);export{d as __pageData,h as default};
